import React, { useState, useMemo } from 'react';
import { useSelector } from 'react-redux';
import toast from 'react-hot-toast';

const STATUS_CONFIG = {
  present: { label:'Present', short:'P', bg:'#D1FAE5', c:'#065F46', radio:'#10B981' },
  absent:  { label:'Absent',  short:'A', bg:'#FEE2E2', c:'#991B1B', radio:'#EF4444' },
  leave:   { label:'Leave',   short:'L', bg:'#FEF3C7', c:'#92400E', radio:'#F59E0B' },
  late:    { label:'Late',    short:'Lt',bg:'#EDE9FE', c:'#5B21B6', radio:'#7C3AED' },
};

const PAGE_SIZE = 10;

export default function Attendance() {
  const students = useSelector(s => s.admission.students);
  const classes  = useSelector(s => s.admission.classes);

  const today = new Date().toISOString().split('T')[0];

  const [selClass,   setSelClass]   = useState('');
  const [selSection, setSelSection] = useState('');
  const [date,       setDate]       = useState(today);
  const [page,       setPage]       = useState(0);   // 0-based
  const [attendance, setAttendance] = useState({});  // { studentId: 'present'|'absent'|'leave'|'late' }
  const [saved,      setSaved]      = useState(false);

  // Derive unique sections for selected class
  const sections = useMemo(() => {
    const s = [...new Set(students.filter(st => !selClass || st.cls === selClass).map(st => st.sec))].filter(Boolean).sort();
    return s;
  }, [students, selClass]);

  // Filtered students based on class + section
  const filtered = useMemo(() => {
    return students.filter(st =>
      (!selClass   || st.cls === selClass) &&
      (!selSection || st.sec === selSection)
    );
  }, [students, selClass, selSection]);

  // Pagination
  const totalPages = Math.ceil(filtered.length / PAGE_SIZE);
  const pageStudents = filtered.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);

  // When class/section changes, reset page
  const handleClassChange = (cls) => { setSelClass(cls); setSelSection(''); setPage(0); setSaved(false); };
  const handleSectionChange = (sec) => { setSelSection(sec); setPage(0); setSaved(false); };

  const setStatus = (id, status) => {
    setAttendance(prev => ({ ...prev, [id]: status }));
    setSaved(false);
  };

  const markAll = (status) => {
    const updates = {};
    filtered.forEach(st => { updates[st.id] = status; });
    setAttendance(prev => ({ ...prev, ...updates }));
    setSaved(false);
    toast.success(`All ${filtered.length} students marked as ${status}`);
  };

  const handleSave = () => {
    // Mark any unmarked students as present
    const final = {};
    filtered.forEach(st => { final[st.id] = attendance[st.id] || 'present'; });
    setAttendance(prev => ({ ...prev, ...final }));
    setSaved(true);

    const counts = Object.values(final).reduce((a, v) => ({ ...a, [v]: (a[v]||0)+1 }), {});
    toast.success(
      `✅ Attendance saved for ${selClass||'All Classes'}${selSection ? ` - ${selSection}` : ''} · ` +
      `Present: ${counts.present||0} · Absent: ${counts.absent||0} · Leave: ${counts.leave||0} · Late: ${counts.late||0}`
    );
  };

  // Summary counts for the current filtered group
  const summary = useMemo(() => {
    const counts = { present:0, absent:0, leave:0, late:0, unmarked:0 };
    filtered.forEach(st => {
      const s = attendance[st.id];
      if (s && counts[s] !== undefined) counts[s]++;
      else counts.unmarked++;
    });
    return counts;
  }, [filtered, attendance]);

  const pct = filtered.length > 0 ? Math.round(((summary.present) / filtered.length) * 100) : 0;

  return (
    <div>
      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:18,flexWrap:'wrap',gap:12}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Attendance Management</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Mark and track daily student attendance</p>
        </div>
        <div style={{display:'flex',gap:10,flexWrap:'wrap'}}>
          <button onClick={()=>markAll('present')} style={{padding:'8px 14px',border:'1.5px solid #10B981',borderRadius:9,background:'#D1FAE5',color:'#065F46',fontSize:12,fontWeight:700,cursor:'pointer'}}>✅ All Present</button>
          <button onClick={()=>markAll('absent')}  style={{padding:'8px 14px',border:'1.5px solid #EF4444',borderRadius:9,background:'#FEE2E2',color:'#991B1B',fontSize:12,fontWeight:700,cursor:'pointer'}}>❌ All Absent</button>
          <button onClick={handleSave} style={{padding:'8px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>💾 Save Attendance</button>
        </div>
      </div>

      {/* Filters row */}
      <div style={{display:'flex',gap:12,marginBottom:16,flexWrap:'wrap',alignItems:'flex-end'}}>
        {/* Date */}
        <div style={{display:'flex',flexDirection:'column',gap:5}}>
          <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>Date</label>
          <input type="date" value={date} onChange={e=>{setDate(e.target.value);setSaved(false);}}
            style={{padding:'9px 12px',border:'1.5px solid #E5E7EB',borderRadius:9,fontSize:13,outline:'none',background:'#fff',fontFamily:'inherit'}}/>
        </div>
        {/* Class */}
        <div style={{display:'flex',flexDirection:'column',gap:5}}>
          <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>Class</label>
          <select value={selClass} onChange={e=>handleClassChange(e.target.value)}
            style={{padding:'9px 12px',border:'1.5px solid #E5E7EB',borderRadius:9,fontSize:13,outline:'none',background:'#fff',minWidth:140,fontFamily:'inherit'}}>
            <option value=''>All Classes</option>
            {classes.map(c=><option key={c}>{c}</option>)}
          </select>
        </div>
        {/* Section */}
        <div style={{display:'flex',flexDirection:'column',gap:5}}>
          <label style={{fontSize:11,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>Section</label>
          <select value={selSection} onChange={e=>handleSectionChange(e.target.value)}
            style={{padding:'9px 12px',border:'1.5px solid #E5E7EB',borderRadius:9,fontSize:13,outline:'none',background:'#fff',minWidth:120,fontFamily:'inherit'}}
            disabled={sections.length===0}>
            <option value=''>All Sections</option>
            {sections.map(s=><option key={s}>{s}</option>)}
          </select>
        </div>
        {/* Student count badge */}
        <div style={{padding:'9px 14px',background:'#EDE9F8',borderRadius:9,fontSize:12,fontWeight:700,color:'#1E1B4B',alignSelf:'flex-end'}}>
          {filtered.length} student{filtered.length!==1?'s':''}
          {selClass ? ` · ${selClass}${selSection?` ${selSection}`:''}` : ' · All classes'}
        </div>
        {/* Saved indicator */}
        {saved && (
          <div style={{padding:'9px 14px',background:'#D1FAE5',borderRadius:9,fontSize:12,fontWeight:700,color:'#065F46',alignSelf:'flex-end'}}>
            ✅ Saved
          </div>
        )}
      </div>

      <div style={{display:'grid',gridTemplateColumns:'2fr 1fr',gap:16}}>

        {/* LEFT — Attendance grid */}
        <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden',display:'flex',flexDirection:'column'}}>
          {/* Column headers */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 90px 90px 90px 90px',gap:0,padding:'10px 16px',background:'#F9FAFB',borderBottom:'1px solid #E5E7EB',alignItems:'center'}}>
            <div style={{fontSize:10,fontWeight:700,color:'#6B7280',textTransform:'uppercase',letterSpacing:'.06em'}}>
              Student
              {filtered.length>0&&<span style={{marginLeft:8,fontWeight:500,color:'#9CA3AF'}}>
                (Showing {page*PAGE_SIZE+1}–{Math.min((page+1)*PAGE_SIZE, filtered.length)} of {filtered.length})
              </span>}
            </div>
            {Object.entries(STATUS_CONFIG).map(([key,{label,short,c,bg}])=>(
              <div key={key} style={{textAlign:'center',fontSize:10,fontWeight:700,color:c,background:bg,padding:'4px 0',borderRadius:6,margin:'0 3px'}}>{short} {label}</div>
            ))}
          </div>

          {/* Student rows */}
          <div style={{flex:1,overflowY:'auto'}}>
            {filtered.length === 0 ? (
              <div style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
                <div style={{fontSize:36,marginBottom:10}}>👨‍🎓</div>
                <div style={{fontWeight:600,fontSize:14,color:'#6B7280'}}>No students found</div>
                <div style={{fontSize:12,marginTop:4}}>Add students from the Students module first</div>
              </div>
            ) : (
              pageStudents.map((st, idx) => {
                const current = attendance[st.id] || '';
                const globalIdx = page * PAGE_SIZE + idx + 1;
                return (
                  <div key={st.id}
                    style={{display:'grid',gridTemplateColumns:'1fr 90px 90px 90px 90px',gap:0,padding:'10px 16px',borderBottom:'0.5px solid #F3F4F6',alignItems:'center',background:idx%2===0?'#fff':'#FAFAFA',transition:'background .1s'}}
                    onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'}
                    onMouseLeave={e=>e.currentTarget.style.background=idx%2===0?'#fff':'#FAFAFA'}>

                    {/* Student info */}
                    <div style={{display:'flex',alignItems:'center',gap:9}}>
                      <div style={{width:20,height:20,borderRadius:'50%',background:'#E5E7EB',display:'flex',alignItems:'center',justifyContent:'center',fontSize:9,fontWeight:700,color:'#6B7280',flexShrink:0}}>{globalIdx}</div>
                      <div style={{width:30,height:30,borderRadius:8,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:12,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{st.name[0]}</div>
                      <div>
                        <div style={{fontSize:13,fontWeight:600,color:'#111827'}}>{st.name}</div>
                        <div style={{fontSize:10,color:'#9CA3AF'}}>{st.adm} · {st.cls} {st.sec}</div>
                      </div>
                    </div>

                    {/* Radio buttons */}
                    {Object.entries(STATUS_CONFIG).map(([key,{radio,bg}])=>(
                      <div key={key} style={{display:'flex',alignItems:'center',justifyContent:'center'}}>
                        <label style={{cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',width:32,height:32,borderRadius:8,background:current===key?bg:'transparent',transition:'background .15s',border:`2px solid ${current===key?radio:'transparent'}`}}>
                          <input
                            type="radio"
                            name={`att-${st.id}`}
                            value={key}
                            checked={current===key}
                            onChange={()=>setStatus(st.id, key)}
                            style={{display:'none'}}
                          />
                          <span style={{fontSize:14,color:current===key?radio:'#D1D5DB'}}>
                            {current===key ? '●' : '○'}
                          </span>
                        </label>
                      </div>
                    ))}
                  </div>
                );
              })
            )}
          </div>

          {/* Pagination footer */}
          {filtered.length > PAGE_SIZE && (
            <div style={{padding:'12px 16px',borderTop:'1px solid #E5E7EB',display:'flex',alignItems:'center',justifyContent:'space-between',background:'#F9FAFB',flexShrink:0}}>
              <span style={{fontSize:12,color:'#6B7280'}}>
                Page <strong>{page+1}</strong> of <strong>{totalPages}</strong>
                &nbsp;·&nbsp; {page*PAGE_SIZE+1}–{Math.min((page+1)*PAGE_SIZE,filtered.length)} of {filtered.length} students
              </span>
              <div style={{display:'flex',gap:8,alignItems:'center'}}>
                <button
                  onClick={()=>setPage(p=>Math.max(0,p-1))}
                  disabled={page===0}
                  style={{width:36,height:36,border:'1.5px solid #E5E7EB',borderRadius:9,background:page===0?'#F9FAFB':'#fff',color:page===0?'#D1D5DB':'#1E1B4B',fontSize:16,cursor:page===0?'not-allowed':'pointer',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:700,transition:'all .15s'}}>
                  ←
                </button>
                {Array.from({length:totalPages},(_,i)=>i).map(i=>(
                  <button key={i} onClick={()=>setPage(i)}
                    style={{width:36,height:36,border:`1.5px solid ${page===i?'#1E1B4B':'#E5E7EB'}`,borderRadius:9,background:page===i?'#1E1B4B':'#fff',color:page===i?'#fff':'#374151',fontSize:12,fontWeight:700,cursor:'pointer',transition:'all .15s'}}>
                    {i+1}
                  </button>
                ))}
                <button
                  onClick={()=>setPage(p=>Math.min(totalPages-1,p+1))}
                  disabled={page===totalPages-1}
                  style={{width:36,height:36,border:'1.5px solid #E5E7EB',borderRadius:9,background:page===totalPages-1?'#F9FAFB':'#fff',color:page===totalPages-1?'#D1D5DB':'#1E1B4B',fontSize:16,cursor:page===totalPages-1?'not-allowed':'pointer',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:700,transition:'all .15s'}}>
                  →
                </button>
              </div>
            </div>
          )}
        </div>

        {/* RIGHT — Summary */}
        <div style={{display:'flex',flexDirection:'column',gap:14}}>

          {/* Today summary */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
            <div style={{padding:'12px 16px',borderBottom:'0.5px solid #F3F4F6',fontWeight:700,fontSize:13,color:'#111827'}}>
              📊 Summary · {date}
            </div>
            <div style={{padding:16}}>
              {/* Donut */}
              <div style={{display:'flex',alignItems:'center',gap:14,marginBottom:16}}>
                <div style={{position:'relative',width:80,height:80,flexShrink:0}}>
                  <svg width="80" height="80" viewBox="0 0 36 36" style={{transform:'rotate(-90deg)'}}>
                    <circle cx="18" cy="18" r="15.9" fill="none" stroke="#F3F4F6" strokeWidth="3"/>
                    <circle cx="18" cy="18" r="15.9" fill="none" stroke="#10B981" strokeWidth="3"
                      strokeDasharray={`${pct} ${100-pct}`} strokeLinecap="round"/>
                  </svg>
                  <div style={{position:'absolute',inset:0,display:'flex',alignItems:'center',justifyContent:'center',fontSize:14,fontWeight:800,color:'#1E1B4B'}}>{pct}%</div>
                </div>
                <div>
                  <div style={{fontSize:15,fontWeight:800,color:'#111827'}}>{summary.present} Present</div>
                  <div style={{fontSize:11,color:'#6B7280',marginTop:3}}>out of {filtered.length} students</div>
                  {summary.unmarked>0&&<div style={{fontSize:11,color:'#F59E0B',marginTop:3,fontWeight:600}}>⚠️ {summary.unmarked} not marked yet</div>}
                </div>
              </div>

              {/* Status bars */}
              <div style={{display:'flex',flexDirection:'column',gap:8}}>
                {Object.entries(STATUS_CONFIG).map(([key,{label,bg,c,radio}])=>{
                  const count = summary[key]||0;
                  const pctVal = filtered.length>0 ? Math.round((count/filtered.length)*100) : 0;
                  return (
                    <div key={key}>
                      <div style={{display:'flex',justifyContent:'space-between',marginBottom:4,fontSize:11}}>
                        <span style={{fontWeight:600,color:'#374151'}}>{label}</span>
                        <span style={{fontWeight:700,color:c}}>{count} <span style={{fontWeight:400,color:'#9CA3AF'}}>({pctVal}%)</span></span>
                      </div>
                      <div style={{height:8,background:'#F3F4F6',borderRadius:4,overflow:'hidden'}}>
                        <div style={{height:'100%',width:`${pctVal}%`,background:radio,borderRadius:4,transition:'width .5s'}}/>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Quick legend */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
            <div style={{fontWeight:700,fontSize:12,color:'#111827',marginBottom:10}}>Legend</div>
            <div style={{display:'flex',flexDirection:'column',gap:7}}>
              {Object.entries(STATUS_CONFIG).map(([key,{label,short,bg,c}])=>(
                <div key={key} style={{display:'flex',alignItems:'center',gap:8}}>
                  <div style={{width:28,height:24,borderRadius:6,background:bg,display:'flex',alignItems:'center',justifyContent:'center',fontSize:10,fontWeight:800,color:c,flexShrink:0}}>{short}</div>
                  <span style={{fontSize:12,color:'#374151',fontWeight:500}}>{label}</span>
                  <span style={{marginLeft:'auto',fontSize:11,fontWeight:700,color:c}}>{summary[key]||0}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Instructions */}
          <div style={{background:'#EDE9F8',borderRadius:12,padding:14,fontSize:11,color:'#4C1D95',lineHeight:1.7}}>
            <div style={{fontWeight:700,marginBottom:6}}>How to use:</div>
            <div>1. Select <strong>Class</strong> and <strong>Section</strong></div>
            <div>2. Click the circle for each student</div>
            <div>3. Use <strong>← →</strong> arrows for next/prev 10</div>
            <div>4. Click <strong>Save Attendance</strong> when done</div>
          </div>
        </div>
      </div>
    </div>
  );
}
